const shortSido = (s) => s.replace(/(특별자치시|특별자치도|특별시|광역시|자치도|도)$/, "");
function parseSgg(sido, sgg) {
  const sidoS = shortSido(sido);
  let si = null, gu = null;
  if (sgg.includes(" ")) { const [a, b] = sgg.split(" "); si = a; gu = b; }
  else if (/구$/.test(sgg)) { gu = sgg; si = sidoS; }
  else { si = sgg; }
  const siS = si ? si.replace(/(시|군)$/, "") : sidoS;
  return { siS, gu };
}
// 번호 행정동 통합: 수진1동·수진2동 → 수진동
function mergeNumbered(list) {
  const seen = new Set(); const out = [];
  for (const d of list) {
    const base = d.replace(/\d+(?:[·ㆍ∙‧]\d+)*(동|가)$/, "$1");
    if (seen.has(base)) continue;
    seen.add(base); out.push(base);
  }
  return out;
}
// 선택한 시군구들 + 형식 → 지역 문자열 배열 생성 (지리적으로 유효한 조합만)
function genRegionTerms(sido, sggList, fmts, mergeNum) {
  const out = [];
  const push = (v) => { if (v && !out.includes(v)) out.push(v); };
  for (const sgg of sggList) {
    const dongsRaw = (KOREA_REGIONS[sido] && KOREA_REGIONS[sido][sgg]) || [];
    const dongs = mergeNum ? mergeNumbered(dongsRaw) : dongsRaw;
    const { siS, gu } = parseSgg(sido, sgg);
    if (fmts.si) push(siS);
    if (fmts.gu && gu) push(gu);
    for (const d of dongs) {
      if (fmts.dong) push(d);
      if (fmts.guDong && gu) push(gu + " " + d);
      if (fmts.siDong) push(siS + " " + d);
    }
  }
  return out;
}

